import logging
import azure.functions as func
from azure.identity import ManagedIdentityCredential
from azure.storage.blob import BlobServiceClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient, EventGridEvent
import json

def main(myblob: func.InputStream):
    logging.info(f"Processing blob: {myblob.name}")

    # Managed Identity Credential
    credential = ManagedIdentityCredential()

    # Blob Storage Client
    blob_service_client = BlobServiceClient(account_url="https://<your-storage-account-name>.blob.core.windows.net", credential=credential)
    container_client = blob_service_client.get_container_client("<your-container-name>")
    
    # Read blob content
    blob_content = myblob.read()
    logging.info(f"Blob content: {blob_content}")

    # Process the blob content (dummy processing)
    processed_data = {"processed": True, "content": blob_content.decode('utf-8')}

    # Cosmos DB Client
    cosmos_client = CosmosClient(url="https://<your-cosmos-account-name>.documents.azure.com:443/", credential=credential)
    database = cosmos_client.get_database_client("<your-database-name>")
    container = database.get_container_client("<your-container-name>")

    # Write to Cosmos DB
    container.upsert_item(processed_data)
    logging.info("Data written to Cosmos DB")

    # Event Grid Client
    event_grid_client = EventGridPublisherClient(endpoint="https://<your-event-grid-domain>.<region>-1.eventgrid.azure.net/api/events", credential=credential)

    # Create Event Grid Event
    event = EventGridEvent(
        subject="BlobProcessed",
        event_type="BlobProcessedEvent",
        data=processed_data,
        data_version="1.0"
    )

    # Send Event Grid Notification
    event_grid_client.send(event)
    logging.info("Notification sent via Event Grid")